int main() {
    int fd[2];
    pipe(fd);

    pid_t pid = fork();

    if (pid < 0) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close the write end of the pipe
        close(fd[1]);

        // Duplicate the file descriptor to stdin and stdout
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        close(fd[0]); // Close the duplicate file descriptor

        execlp("command", "command", (char *)0); // Replace "command" with the command you want to run
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close the read end of the pipe
        close(fd[0]);

        std::cout << "Parent process writes to the pipe" << std::endl;
        write(fd[1], "Hello, child!", 13); // Send data to the child process

        close(fd[1]);

        wait(NULL); // Wait for the child to finish
